     1→/**
     2→ * Digest Generator Service
     3→ *
     4→ * Handles email digest generation with:
     5→ * - Category grouping logic
     6→ * - Template data preparation for Handlebars
     7→ * - HTML generation using TemplateEngine
     8→ * - Performance optimization with batched database queries
     9→ *
    10→ * Integrates with:
    11→ * - Prisma ORM for database queries
    12→ * - TemplateEngine for HTML rendering
    13→ * - Classification results from ClassificationRepository
    14→ */
    15→
    16→import { PrismaClient, Prisma } from '@prisma/client';
    17→import { TemplateEngine } from './template-engine';
    18→import type {
    19→  EmailDigest,
    20→  DigestCategory,
    21→  DigestEmail,
    22→  DigestCategoryTemplateData,
    23→  EmailGroup,
    24→  CategoryStatistics,
    25→  DigestEmailRenderingData,
    26→} from '../types/email-digest';
    27→import { randomUUID } from 'crypto';
    28→
    29→/**
    30→ * Request parameters for digest generation
    31→ */
    32→export interface GenerateDigestRequest {
    33→  digestType: 'daily' | 'weekly' | 'on_demand';
    34→  dateRange: {
    35→    start: Date;
    36→    end: Date;
    37→  };
    38→  recipientEmail: string;
    39→  templateName?: string;
    40→  categories?: string[]; // Optional category filter
    41→  options?: {
    42→    maxEmailsPerCategory?: number;
    43→    includeFullContent?: boolean;
    44→    sortBy?: 'date' | 'confidence' | 'urgency';
    45→  };
    46→}
    47→
    48→/**
    49→ * Internal email data structure from database
    50→ */
    51→interface EmailWithClassification {
    52→  gmailId: string;
    53→  subject: string | null;
    54→  fromSimple: Prisma.JsonValue;
    55→  sentAt: Date;
    56→  bodyText: string | null;
    57→  sessionCategories: Array<{
    58→    categoryId: number;
    59→    isPrimary: boolean;
    60→    confidence: Prisma.Decimal | null;
    61→    aiClassified: boolean | null;
    62→    sessionId: bigint;
    63→  }>;
    64→}
    65→
    66→/**
    67→ * Category metadata from database
    68→ */
    69→interface CategoryMetadata {
    70→  categoryId: number;
    71→  code: string;
    72→  displayName: string | null;
    73→  description: string | null;
    74→  priority: number;
    75→  iconClass: string | null;
    76→  colorScheme: string | null;
    77→}
    78→
    79→/**
    80→ * Digest Generator Implementation
    81→ *
    82→ * Generates categorized email digests with HTML templates
    83→ */
    84→export class DigestGenerator {
    85→  private readonly prisma: PrismaClient;
    86→  private readonly templateEngine: TemplateEngine;
    87→  private readonly ownsPrisma: boolean;
    88→
    89→  /**
    90→   * Initialize DigestGenerator
    91→   *
    92→   * @param prisma - Prisma client instance (creates default if not provided)
    93→   * @param templateEngine - TemplateEngine instance (creates default if not provided)
    94→   */
    95→  constructor(prisma?: PrismaClient, templateEngine?: TemplateEngine) {
    96→    if (prisma) {
    97→      this.prisma = prisma;
    98→      this.ownsPrisma = false;
    99→    } else {
   100→      this.prisma = new PrismaClient();
   101→      this.ownsPrisma = true;
   102→    }
   103→
   104→    this.templateEngine = templateEngine || new TemplateEngine({ templateDir: './templates' });
   105→  }
   106→
   107→  /**
   108→   * Generate email digest with category grouping
   109→   *
   110→   * @param request - Digest generation request parameters
   111→   * @returns Complete EmailDigest with categorized emails and HTML content
   112→   * @throws {Error} If validation fails or generation encounters errors
   113→   */
   114→  async generateDigest(request: GenerateDigestRequest): Promise<EmailDigest> {
   115→    const startTime = Date.now();
   116→
   117→    // Validate request parameters
   118→    this.validateRequest(request);
   119→
   120→    try {
   121→      // Step 1: Fetch data from database (batched queries for performance)
   122→      const dataPreparationStart = Date.now();
   123→      const { emails, categories, urgencyMap } = await this.fetchDigestData(request);
   124→      const dataPreparationTimeMs = Date.now() - dataPreparationStart;
   125→
   126→      // Step 2: Group emails by category with priority sorting
   127→      const groupedCategories = this.groupEmailsByCategory(emails, categories, urgencyMap, request);
   128→
   129→      // Step 3: Prepare template data for Handlebars
   130→      const templateData = this.prepareTemplateData(request, groupedCategories);
   131→
   132→      // Step 4: Render HTML using TemplateEngine
   133→      const templateRenderingStart = Date.now();
   134→      const htmlContent = await this.renderHTML(request, templateData);
   135→      const templateRenderingTimeMs = Date.now() - templateRenderingStart;
   136→
   137→      // Step 5: Build complete EmailDigest object
   138→      const totalEmailCount = groupedCategories.reduce((sum, cat) => sum + cat.emailCount, 0);
   139→      const generationDurationMs = Date.now() - startTime;
   140→
   141→      const digest: EmailDigest = {
   142→        id: randomUUID(),
   143→        generatedAt: new Date(),
   144→        digestType: request.digestType,
   145→        recipientEmail: request.recipientEmail,
   146→        categories: groupedCategories,
   147→        totalEmailCount,
   148→        dateRange: {
   149→          start: request.dateRange.start,
   150→          end: request.dateRange.end,
   151→        },
   152→        templateUsed: request.templateName || `default-${request.digestType}`,
   153→        htmlContent,
   154→        deliveryStatus: 'pending',
   155→        generationMetadata: {
   156→          generationDurationMs,
   157→          templateRenderingTimeMs,
   158→          dataPreparationTimeMs,
   159→          templateEngine: 'handlebars',
   160→          templateVersion: '1.0.0',
   161→          partialsUsed: [],
   162→          helpersUsed: [],
   163→          emailsProcessed: totalEmailCount,
   164→          categoriesIncluded: groupedCategories.length,
   165→          filteringRules: [],
   166→          sortingCriteria: [request.options?.sortBy || 'date'],
   167→          memoryUsageMB: process.memoryUsage().heapUsed / 1024 / 1024,
   168→          cacheHitRate: 0,
   169→          templateCacheUsed: false,
   170→          contentQualityScore: 1.0,
   171→          templateRenderingErrors: [],
   172→          dataValidationWarnings: [],
   173→        },
   174→      };
   175→
   176→      return digest;
   177→    } catch (error) {
   178→      if (error instanceof Error && error.message.includes('Template')) {
   179→        throw new Error(`Template rendering failed: ${error.message}`);
   180→      }
   181→      throw new Error(`Failed to generate digest: ${error instanceof Error ? error.message : String(error)}`);
   182→    }
   183→  }
   184→
   185→  /**
   186→   * Fetch digest data from database with batched queries
   187→   *
   188→   * Performance optimization: Uses 3 queries total instead of N+1 pattern
   189→   */
   190→  private async fetchDigestData(request: GenerateDigestRequest): Promise<{
   191→    emails: EmailWithClassification[];
   192→    categories: Map<number, CategoryMetadata>;
   193→    urgencyMap: Map<string, string>;
   194→  }> {
   195→    try {
   196→      // Query 1: Fetch all active categories
   197→      const categoryRecords = await this.prisma.category.findMany({
   198→        where: { active: true },
   199→        select: {
   200→          categoryId: true,
   201→          code: true,
   202→          displayName: true,
   203→          description: true,
   204→        },
   205→        orderBy: { categoryId: 'asc' }, // Use categoryId for sorting since priority field doesn't exist yet
   206→      });
   207→
   208→      const categoriesMap = new Map<number, CategoryMetadata>(
   209→        categoryRecords.map((cat) => [
   210→          cat.categoryId,
   211→          {
   212→            categoryId: cat.categoryId,
   213→            code: cat.code,
   214→            displayName: cat.displayName,
   215→            description: cat.description,
   216→            priority: cat.categoryId, // Use categoryId as fallback priority
   217→            iconClass: null,
   218→            colorScheme: null,
   219→          },
   220→        ])
   221→      );
   222→
   223→      // Query 2: Fetch emails in date range with classifications
   224→      const emailRecords = await this.prisma.gmailMessage.findMany({
   225→        where: {
   226→          sentAt: {
   227→            gte: request.dateRange.start,
   228→            lte: request.dateRange.end,
   229→          },
   230→        },
   231→        select: {
   232→          gmailId: true,
   233→          subject: true,
   234→          fromSimple: true,
   235→          sentAt: true,
   236→          bodyText: true,
   237→        },
   238→        orderBy: { sentAt: 'desc' },
   239→      });
   240→
   241→      // Query 3: Fetch all session categories for these emails
   242→      const emailIds = emailRecords.map((email) => email.gmailId);
   243→      const sessionCategories = await this.prisma.sessionCategory.findMany({
   244→        where: {
   245→          session: {
   246→            gmailId: { in: emailIds },
   247→          },
   248→        },
   249→        select: {
   250→          session: {
   251→            select: {
   252→              gmailId: true,
   253→              sessionId: true,
   254→            },
   255→          },
   256→          categoryId: true,
   257→          isPrimary: true,
   258→          confidence: true,
   259→          aiClassified: true,
   260→        },
   261→      });
   262→
   263→      // Build map of email ID -> session categories
   264→      const emailCategoriesMap = new Map<string, EmailWithClassification['sessionCategories']>();
   265→      for (const sc of sessionCategories) {
   266→        const gmailId = sc.session.gmailId;
   267→        if (!emailCategoriesMap.has(gmailId)) {
   268→          emailCategoriesMap.set(gmailId, []);
   269→        }
   270→        emailCategoriesMap.get(gmailId)!.push({
   271→          categoryId: sc.categoryId,
   272→          isPrimary: sc.isPrimary,
   273→          confidence: sc.confidence,
   274→          aiClassified: sc.aiClassified,
   275→          sessionId: sc.session.sessionId,
   276→        });
   277→      }
   278→
   279→      // Combine emails with their classifications
   280→      const emails: EmailWithClassification[] = emailRecords.map((email) => ({
   281→        gmailId: email.gmailId,
   282→        subject: email.subject,
   283→        fromSimple: email.fromSimple,
   284→        sentAt: email.sentAt,
   285→        bodyText: email.bodyText,
   286→        sessionCategories: emailCategoriesMap.get(email.gmailId) || [],
   287→      }));
   288→
   289→      // Query 4: Fetch urgency attributes for all sessions
   290→      const sessionIds = Array.from(new Set(sessionCategories.map((sc) => sc.session.sessionId)));
   291→      const urgencyAttributes = await this.prisma.detectedAttribute.findMany({
   292→        where: {
   293→          sessionId: { in: sessionIds },
   294→          attributeName: 'urgency',
   295→        },
   296→        select: {
   297→          sessionId: true,
   298→          attributeValue: true,
   299→        },
   300→      });
   301→
   302→      // Build map of session ID -> urgency level
   303→      const urgencyMap = new Map<string, string>(
   304→        urgencyAttributes.map((attr) => [attr.sessionId.toString(), attr.attributeValue || 'medium'])
   305→      );
   306→
   307→      return { emails, categories: categoriesMap, urgencyMap };
   308→    } catch (error) {
   309→      throw new Error(`Database query failed: ${error instanceof Error ? error.message : String(error)}`);
   310→    }
   311→  }
   312→
   313→  /**
   314→   * Group emails by category with priority sorting
   315→   */
   316→  private groupEmailsByCategory(
   317→    emails: EmailWithClassification[],
   318→    categories: Map<number, CategoryMetadata>,
   319→    urgencyMap: Map<string, string>,
   320→    request: GenerateDigestRequest
   321→  ): DigestCategory[] {
   322→    // Group emails by primary category
   323→    const categoryGroups = new Map<number, EmailWithClassification[]>();
   324→
   325→    for (const email of emails) {
   326→      // Find primary category classification
   327→      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
   328→      if (!primaryClassification) {
   329→        continue; // Skip unclassified emails
   330→      }
   331→
   332→      const categoryId = primaryClassification.categoryId;
   333→      if (!categoryGroups.has(categoryId)) {
   334→        categoryGroups.set(categoryId, []);
   335→      }
   336→      categoryGroups.get(categoryId)!.push(email);
   337→    }
   338→
   339→    // Build DigestCategory objects sorted by priority
   340→    const digestCategories: DigestCategory[] = [];
   341→
   342→    for (const [categoryId, categoryEmails] of Array.from(categoryGroups.entries())) {
   343→      const categoryMeta = categories.get(categoryId);
   344→      if (!categoryMeta) {
   345→        continue; // Skip if category metadata missing
   346→      }
   347→
   348→      // Filter by category if specified in request
   349→      if (request.categories && !request.categories.includes(categoryMeta.code)) {
   350→        continue;
   351→      }
   352→
   353→      // Convert to DigestEmail objects
   354→      const digestEmails = this.convertToDigestEmails(categoryEmails, urgencyMap);
   355→
   356→      // Group emails by urgency for template organization
   357→      const emailGroups = this.groupEmailsByUrgency(digestEmails);
   358→
   359→      // Calculate category statistics
   360→      const statistics = this.calculateCategoryStatistics(categoryEmails, digestEmails);
   361→
   362→      // Prepare template data
   363→      const templateData = this.prepareCategoryTemplateData(categoryMeta, digestEmails, emailGroups, statistics);
   364→
   365→      const digestCategory: DigestCategory = {
   366→        categoryName: categoryMeta.code,
   367→        emailCount: categoryEmails.length,
   368→        emails: digestEmails,
   369→        priority: categoryMeta.priority,
   370→        templateData,
   371→        categoryMetadata: {
   372→          averageConfidence: statistics.averageConfidence,
   373→          processingDurationMs: 0, // TODO: Calculate from session data
   374→          aiClassificationUsed: categoryEmails.some((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)),
   375→          urgencyDistribution: this.calculateUrgencyDistribution(digestEmails),
   376→        },
   377→      };
   378→
   379→      digestCategories.push(digestCategory);
   380→    }
   381→
   382→    // Sort categories by priority
   383→    digestCategories.sort((a, b) => a.priority - b.priority);
   384→
   385→    return digestCategories;
   386→  }
   387→
   388→  /**
   389→   * Convert database emails to DigestEmail format
   390→   */
   391→  private convertToDigestEmails(emails: EmailWithClassification[], urgencyMap: Map<string, string>): DigestEmail[] {
   392→    return emails.map((email) => {
   393→      const primaryClassification = email.sessionCategories.find((sc) => sc.isPrimary);
   394→      const confidence = primaryClassification?.confidence ? Number(primaryClassification.confidence) : 0.0;
   395→
   396→      // Get all categories for this email (primary + secondary)
   397→      const allCategories = email.sessionCategories.map((sc) => {
   398→        // Note: In a real implementation, we'd look up category code from categoryId
   399→        // For now, using a placeholder
   400→        return `cat-${sc.categoryId}`;
   401→      });
   402→
   403→      // Get urgency level from detected attributes
   404→      const sessionId = primaryClassification?.sessionId.toString();
   405→      const urgency = sessionId ? urgencyMap.get(sessionId) || 'medium' : 'medium';
   406→
   407→      // Extract email from fromSimple JSON (expected format: [{"email": "user@example.com"}])
   408→      const fromEmail = this.escapeHtml(this.extractEmailFromJson(email.fromSimple));
   409→
   410→      // Escape special characters in subject and snippet
   411→      const escapedSubject = this.escapeHtml(email.subject || '(No Subject)');
   412→      const escapedSnippet = this.escapeHtml((email.bodyText || '').substring(0, 150));
   413→
   414→      const digestEmail: DigestEmail = {
   415→        emailId: email.gmailId,
   416→        subject: escapedSubject,
   417→        from: fromEmail,
   418→        date: email.sentAt,
   419→        snippet: escapedSnippet,
   420→        confidence,
   421→        categories: allCategories,
   422→        urgency,
   423→        includeFullContent: false,
   424→        customHighlights: [],
   425→        renderingData: this.prepareEmailRenderingData(email, urgency, confidence),
   426→      };
   427→
   428→      return digestEmail;
   429→    });
   430→  }
   431→
   432→  /**
   433→   * Group emails by urgency level for template organization
   434→   */
   435→  private groupEmailsByUrgency(emails: DigestEmail[]): EmailGroup[] {
   436→    const urgentEmails = emails.filter((e) => e.urgency === 'high');
   437→    const normalEmails = emails.filter((e) => e.urgency === 'medium');
   438→    const lowPriorityEmails = emails.filter((e) => e.urgency === 'low');
   439→
   440→    const groups: EmailGroup[] = [];
   441→
   442→    if (urgentEmails.length > 0) {
   443→      groups.push({
   444→        groupType: 'urgent',
   445→        groupName: 'Urgent',
   446→        emails: urgentEmails,
   447→        groupSummary: `${urgentEmails.length} urgent email(s) requiring immediate attention`,
   448→        groupIcon: '🔴',
   449→      });
   450→    }
   451→
   452→    if (normalEmails.length > 0) {
   453→      groups.push({
   454→        groupType: 'normal',
   455→        groupName: 'Normal Priority',
   456→        emails: normalEmails,
   457→        groupSummary: `${normalEmails.length} email(s)`,
   458→        groupIcon: '📧',
   459→      });
   460→    }
   461→
   462→    if (lowPriorityEmails.length > 0) {
   463→      groups.push({
   464→        groupType: 'low_priority',
   465→        groupName: 'Low Priority',
   466→        emails: lowPriorityEmails,
   467→        groupSummary: `${lowPriorityEmails.length} low priority email(s)`,
   468→        groupIcon: '📭',
   469→      });
   470→    }
   471→
   472→    return groups;
   473→  }
   474→
   475→  /**
   476→   * Calculate category statistics for template display
   477→   */
   478→  private calculateCategoryStatistics(
   479→    emails: EmailWithClassification[],
   480→    digestEmails: DigestEmail[]
   481→  ): CategoryStatistics {
   482→    const confidences = emails
   483→      .map((e) => e.sessionCategories.find((sc) => sc.isPrimary)?.confidence)
   484→      .filter((c): c is Prisma.Decimal => c !== undefined && c !== null)
   485→      .map((c) => Number(c));
   486→
   487→    const averageConfidence =
   488→      confidences.length > 0 ? confidences.reduce((sum, c) => sum + c, 0) / confidences.length : 0;
   489→
   490→    const urgentEmailsCount = digestEmails.filter((e) => e.urgency === 'high').length;
   491→
   492→    const aiClassifiedCount = emails.filter((e) => e.sessionCategories.some((sc) => sc.aiClassified === true)).length;
   493→
   494→    // Calculate top domains
   495→    const domainCounts = new Map<string, number>();
   496→    for (const email of emails) {
   497→      const fromEmail = this.extractEmailFromJson(email.fromSimple);
   498→      const domain = fromEmail.split('@')[1] || fromEmail;
   499→      domainCounts.set(domain, (domainCounts.get(domain) || 0) + 1);
   500→    }
   501→
   502→    const topDomains = Array.from(domainCounts.entries())
   503→      .sort((a, b) => b[1] - a[1])
   504→      .slice(0, 5)
   505→      .map(([domain, count]) => ({ domain, count }));
   506→
   507→    return {
   508→      emailCount: emails.length,
   509→      averageConfidence,
   510→      urgentEmailsCount,
   511→      aiClassifiedCount,
   512→      averageProcessingTime: 0, // TODO: Calculate from session metrics
   513→      topDomains,
   514→    };
   515→  }
   516→
   517→  /**
   518→   * Prepare category template data for Handlebars rendering
   519→   */
   520→  private prepareCategoryTemplateData(
   521→    categoryMeta: CategoryMetadata,
   522→    emails: DigestEmail[],
   523→    emailGroups: EmailGroup[],
   524→    statistics: CategoryStatistics
   525→  ): DigestCategoryTemplateData {
   526→    return {
   527→      name: this.escapeHtml(categoryMeta.code),
   528→      displayName: this.escapeHtml(categoryMeta.displayName || categoryMeta.code),
   529→      description: this.escapeHtml(categoryMeta.description || ''),
   530→      emailGroups,
   531→      totalCount: emails.length,
   532→      iconClass: categoryMeta.iconClass || 'default-icon',
   533→      colorScheme: categoryMeta.colorScheme || '#333333',
   534→      sortOrder: categoryMeta.priority,
   535→      statistics,
   536→      customVariables: {},
   537→    };
   538→  }
   539→
   540→  /**
   541→   * Prepare email rendering data for templates
   542→   */
   543→  private prepareEmailRenderingData(
   544→    email: EmailWithClassification,
   545→    urgency: string,
   546→    confidence: number
   547→  ): DigestEmailRenderingData {
   548→    const fromEmail = this.escapeHtml(this.extractEmailFromJson(email.fromSimple));
   549→    return {
   550→      displaySubject: this.escapeHtml((email.subject || '(No Subject)').substring(0, 100)),
   551→      displayFrom: fromEmail,
   552→      displayDate: email.sentAt.toLocaleDateString(),
   553→      displayTime: email.sentAt.toLocaleTimeString(),
   554→      summarySnippet: this.escapeHtml((email.bodyText || '').substring(0, 150)),
   555→      keyHighlights: [],
   556→      actionableItems: [],
   557→      urgencyIcon: urgency === 'high' ? '🔴' : urgency === 'medium' ? '🟡' : '🟢',
   558→      confidenceIndicator: confidence > 0.9 ? 'High' : confidence > 0.7 ? 'Medium' : 'Low',
   559→      categoryBadges: [],
   560→      quickActions: [],
   561→      expandedContentAvailable: false,
   562→    };
   563→  }
   564→
   565→  /**
   566→   * Extract email address from Prisma JSON field
   567→   * Expected format: [{"email": "user@example.com"}] or {"email": "user@example.com"}
   568→   */
   569→  private extractEmailFromJson(jsonValue: Prisma.JsonValue): string {
   570→    try {
   571→      if (Array.isArray(jsonValue) && jsonValue.length > 0) {
   572→        const firstItem = jsonValue[0] as { email?: string };
   573→        return firstItem.email || 'unknown@example.com';
   574→      } else if (typeof jsonValue === 'object' && jsonValue !== null && 'email' in jsonValue) {
   575→        return (jsonValue as { email?: string }).email || 'unknown@example.com';
   576→      }
   577→      return 'unknown@example.com';
   578→    } catch {
   579→      return 'unknown@example.com';
   580→    }
   581→  }
   582→
   583→  /**
   584→   * Calculate urgency distribution for category metadata
   585→   */
   586→  private calculateUrgencyDistribution(emails: DigestEmail[]): Record<string, number> {
   587→    const distribution: Record<string, number> = {
   588→      high: 0,
   589→      medium: 0,
   590→      low: 0,
   591→    };
   592→
   593→    for (const email of emails) {
   594→      distribution[email.urgency] = (distribution[email.urgency] || 0) + 1;
   595→    }
   596→
   597→    return distribution;
   598→  }
   599→
   600→  /**
   601→   * Prepare complete template data for Handlebars
   602→   */
   603→  private prepareTemplateData(request: GenerateDigestRequest, categories: DigestCategory[]): Record<string, unknown> {
   604→    return {
   605→      digestType: request.digestType,
   606→      recipientEmail: request.recipientEmail,
   607→      generatedAt: new Date().toISOString(),
   608→      dateRange: {
   609→        start: request.dateRange.start.toISOString(),
   610→        end: request.dateRange.end.toISOString(),
   611→      },
   612→      categories,
   613→      totalEmailCount: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
   614→      summary: {
   615→        totalCategories: categories.length,
   616→        totalEmails: categories.reduce((sum, cat) => sum + cat.emailCount, 0),
   617→        urgentEmails: categories.reduce((sum, cat) => sum + cat.categoryMetadata.urgencyDistribution.high, 0),
   618→      },
   619→    };
   620→  }
   621→
   622→  /**
   623→   * Render HTML using TemplateEngine
   624→   */
   625→  private async renderHTML(request: GenerateDigestRequest, templateData: Record<string, unknown>): Promise<string> {
   626→    try {
   627→      const templateName = request.templateName || `default-${request.digestType}`;
   628→
   629→      // For now, use a simple template string. In production, this would load from file system
