          subject: 'Test 2',
          fromSimple: [{ email: 'test2@example.com' }],
          sentAt: new Date(),
          bodyText: 'Body 2',
        },
        {
          gmailId: 'msg-003',
          subject: 'Test 3',
          fromSimple: [{ email: 'test3@example.com' }],
          sentAt: new Date(),
          bodyText: 'Body 3',
        },
      ]);

