 */
function getLogisticsDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.logisticsDomains || [];
}

/**
 * Default Gmail category mapping for backward compatibility
 *
 * Matches historical hardcoded behavior while enabling configuration-driven customization.
 */
const DEFAULT_GMAIL_CATEGORY_MAPPING: GmailCategoryMapping[] = [
  {
    categoryLabel: 'CATEGORY_SOCIAL',
    attributeName: 'gmailCategorySocial',
    confidence: 0.9,
    description: "Gmail's automatic Social categorization; boosts personal category",
