     1→/**
     2→ * Classification Results Persistence Layer
     3→ *
     4→ * Repository pattern for classification results persistence using Prisma ORM:
     5→ * - Classification session management (create, update, complete)
     6→ * - Classification results with explainability traces
     7→ * - Score breakdown persistence
     8→ * - Attribute context storage
     9→ * - Multi-label classification support
    10→ * - Domain signal resolutions
    11→ * - Transaction-safe batch operations
    12→ *
    13→ * Benefits of Prisma ORM:
    14→ * - Type-safe database queries with auto-generated types
    15→ * - Built-in transaction handling for complex multi-table operations
    16→ * - Automatic JSON serialization/deserialization for explainability data
    17→ * - Connection pooling and query optimization
    18→ * - SQL injection protection via parameterized queries
    19→ */
    20→
    21→import { PrismaClient, Prisma } from '@prisma/client';
    22→import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';
    23→import { createLogger } from '../logging/logger-factory';
    24→
    25→const logger = createLogger();
    26→
    27→/**
    28→ * Domain signal resolution data structure
    29→ */
    30→export interface DomainSignalData {
    31→  domain: string;
    32→  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
    33→  matchedCategoryId: number | null;
    34→  confidenceLevel?: string;
    35→  domainType?: string;
    36→}
    37→
    38→/**
    39→ * Classification Repository using Prisma ORM
    40→ *
    41→ * Provides type-safe classification results persistence with automatic transaction
    42→ * handling, connection pooling, and explainability trace integrity.
    43→ */
    44→export class ClassificationRepository {
    45→  private readonly prisma: PrismaClient;
    46→  private readonly ownsPrisma: boolean;
    47→  private categoryCache: Map<string, number> | null = null;
    48→
    49→  /**
    50→   * Initialize classification repository
    51→   *
    52→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    53→   */
    54→  constructor(prisma?: PrismaClient) {
    55→    if (prisma) {
    56→      this.prisma = prisma;
    57→      this.ownsPrisma = false;
    58→    } else {
    59→      this.prisma = new PrismaClient();
    60→      this.ownsPrisma = true;
    61→    }
    62→  }
    63→
    64→  /**
    65→   * Initialize category cache from database
    66→   *
    67→   * Loads all active categories into memory for fast lookup by code.
    68→   * Called automatically on first use of getCategoryIdFromCode().
    69→   *
    70→   * @throws {Error} If category loading fails
    71→   */
    72→  private async initializeCategoryCache(): Promise<void> {
    73→    try {
    74→      const categories = await this.prisma.category.findMany({
    75→        where: { active: true },
    76→        select: { code: true, categoryId: true },
    77→      });
    78→
    79→      this.categoryCache = new Map(categories.map((cat) => [cat.code, cat.categoryId]));
    80→    } catch (error) {
    81→      throw new Error(`Failed to load category cache: ${error instanceof Error ? error.message : String(error)}`);
    82→    }
    83→  }
    84→
    85→  /**
    86→   * Create a new classification session
    87→   *
    88→   * @param session - ClassificationSession object
    89→   * @param gmailId - Gmail message ID being classified
    90→   * @returns Database session ID as string (safe representation of bigint)
    91→   * @throws {Error} If session creation fails
    92→   */
    93→  async createSession(session: ClassificationSession, gmailId: string): Promise<string> {
    94→    try {
    95→      const result = await this.prisma.classificationSession.create({
    96→        data: {
    97→          gmailId: gmailId,
    98→          pipelineVersion: session.configVersion,
    99→          startedAt: session.startedAt,
   100→          status: 'in_progress',
   101→          triggeredBy: 'system',
   102→          aiRoutingUsed: false,
   103→        },
   104→      });
   105→
   106→      return result.sessionId.toString();
   107→    } catch (error) {
   108→      throw new Error(
   109→        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
   110→      );
   111→    }
   112→  }
   113→
   114→  /**
   115→   * Complete a classification session
   116→   *
   117→   * @param sessionId - Session identifier as string (from createSession)
   118→   * @param finalCategoryCode - Final category code selected (e.g., 'finance', 'personal')
   119→   * @param confidence - Final confidence score
   120→   * @param rationale - Final decision rationale
   121→   * @throws {Error} If session update fails
   122→   */
   123→  async completeSession(
   124→    sessionId: string,
   125→    finalCategoryCode: string,
   126→    confidence: number,
   127→    rationale: string
   128→  ): Promise<void> {
   129→    try {
   130→      // Convert string session ID to BigInt for database query
   131→      const dbSessionId = BigInt(sessionId);
   132→
   133→      await this.prisma.classificationSession.update({
   134→        where: { sessionId: dbSessionId },
   135→        data: {
   136→          completedAt: new Date(),
   137→          finalCategoryCode: finalCategoryCode,
   138→          finalConfidence: new Prisma.Decimal(confidence),
   139→          finalRationale: rationale,
   140→          status: 'completed',
   141→        },
   142→      });
   143→    } catch (error) {
   144→      throw new Error(
   145→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   146→      );
   147→    }
   148→  }
   149→
   150→  /**
   151→   * Save complete classification result with explainability trace
   152→   *
   153→   * Uses Prisma transaction to ensure atomicity across multiple tables:
   154→   * - classification_stage (10 pipeline stages)
   155→   * - stage_category_eval (per-category evaluations)
   156→   * - session_categories (multi-label support)
   157→   * - detected_attributes (attribute context)
   158→   * - extracted_features (AI feature extraction data, if AI was used)
   159→   * - domain_signal_resolutions (domain signals)
   160→   *
   161→   * @param result - ClassificationResult with explainability trace
   162→   * @param sessionId - Session identifier as string (from createSession)
   163→   * @throws {Error} If save fails (rolls back entire transaction)
   164→   */
   165→  async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
   166→    try {
   167→      const dbSessionId = BigInt(sessionId);
   168→
   169→      await this.prisma.$transaction(async (tx) => {
   170→        await this.saveClassificationResultInTransaction(tx, result, dbSessionId);
   171→      });
   172→    } catch (error) {
   173→      throw new Error(
   174→        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
   175→      );
   176→    }
   177→  }
   178→
   179→  /**
   180→   * Internal method to save classification result within a transaction
   181→   *
   182→   * Extracted to allow both single and batch saves to share the same logic
   183→   * while maintaining proper transaction boundaries.
   184→   *
   185→   * @param tx - Prisma transaction client
   186→   * @param result - ClassificationResult with explainability trace
   187→   * @param sessionId - Session identifier as bigint
   188→   * @throws {Error} If save fails (caller should handle)
   189→   */
   190→  private async saveClassificationResultInTransaction(
   191→    tx: Prisma.TransactionClient,
   192→    result: ClassificationResult,
   193→    sessionId: bigint
   194→  ): Promise<void> {
   195→    // 1. Create classification stages (10 pipeline stages: hard assertions through action determination)
   196→    const stageData = this.buildStageData(result, sessionId);
   197→    let stageRecords: Array<{ stageId: bigint; stageOrder: number }> = [];
   198→    if (stageData.length > 0) {
   199→      await tx.classificationStage.createMany({ data: stageData });
   200→
   201→      // Retrieve created stage records to get stage IDs for AI feature extraction
   202→      stageRecords = await tx.classificationStage.findMany({
   203→        where: { sessionId: sessionId },
   204→        select: { stageId: true, stageOrder: true },
   205→        orderBy: { stageOrder: 'asc' },
   206→      });
   207→    }
   208→
   209→    // 2. Create stage category evaluations (score breakdown for each category)
   210→    const categoryEvalData = await this.buildCategoryEvalData(result, sessionId);
   211→    if (categoryEvalData.length > 0) {
   212→      await tx.stageCategoryEval.createMany({ data: categoryEvalData });
   213→    }
   214→
   215→    // 3. Create session categories (multi-label support)
   216→    const sessionCategoryData = await this.buildSessionCategoryData(result, sessionId);
   217→    if (sessionCategoryData.length > 0) {
   218→      await tx.sessionCategory.createMany({ data: sessionCategoryData });
   219→    }
   220→
   221→    // 4. Create detected attributes (attribute context)
   222→    const attributeData = this.buildAttributeData(result.attributeContext, sessionId);
   223→    if (attributeData.length > 0) {
   224→      await tx.detectedAttribute.createMany({ data: attributeData });
   225→    }
   226→
   227→    // 5. Create extracted features (AI feature extraction data)
   228→    // Only persist if AI routing was used and we have feature extraction data
   229→    if (result.aiRoutingUsed && stageRecords.length > 0) {
   230→      const extractedFeatureData = this.buildExtractedFeatureData(result, stageRecords);
   231→      if (extractedFeatureData.length > 0) {
   232→        await tx.extractedFeature.createMany({ data: extractedFeatureData });
   233→      }
   234→    }
   235→  }
   236→
   237→  /**
   238→   * Save attribute context separately
   239→   *
   240→   * @param context - AttributeContext with detected attributes
   241→   * @param sessionId - Session identifier as string (from createSession)
   242→   * @throws {Error} If save fails
   243→   */
   244→  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
   245→    try {
   246→      const dbSessionId = BigInt(sessionId);
   247→      const attributeData = this.buildAttributeData(context, dbSessionId);
   248→      if (attributeData.length > 0) {
   249→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   250→      }
   251→    } catch (error) {
   252→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   253→    }
   254→  }
   255→
   256→  /**
   257→   * Save domain signal resolutions
   258→   *
   259→   * @param signals - Array of domain signal resolutions
   260→   * @param sessionId - Session identifier as string (from createSession)
   261→   * @throws {Error} If save fails
   262→   */
   263→  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
   264→    if (signals.length === 0) {
   265→      return;
   266→    }
   267→
   268→    try {
   269→      const dbSessionId = BigInt(sessionId);
   270→      await this.prisma.domainSignalResolution.createMany({
   271→        data: signals.map((signal) => ({
   272→          sessionId: dbSessionId,
   273→          domain: signal.domain,
   274→          signalType: signal.signalType,
   275→          matchedCategoryId: signal.matchedCategoryId,
   276→          confidenceLevel: signal.confidenceLevel || null,
   277→          domainType: signal.domainType || null,
   278→          createdAt: new Date(),
   279→        })),
   280→      });
   281→    } catch (error) {
   282→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   283→    }
   284→  }
   285→
   286→  /**
   287→   * Batch save multiple classification results
   288→   *
   289→   * Wraps all saves in a single outer transaction for atomicity.
   290→   * Either all results are saved or none are (all-or-nothing semantics).
   291→   *
   292→   * @param results - Array of ClassificationResult objects
   293→   * @param sessionId - Session identifier as string (from createSession)
   294→   * @throws {Error} If batch save fails (entire batch is rolled back)
   295→   */
   296→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   297→    if (results.length === 0) {
   298→      return;
   299→    }
   300→
   301→    try {
   302→      const dbSessionId = BigInt(sessionId);
   303→
   304→      // Wrap entire batch in outer transaction to ensure atomicity across
   305→      // email persistence, classification results, and category labels
   306→      await this.prisma.$transaction(async (tx) => {
   307→        for (const result of results) {
   308→          await this.saveClassificationResultInTransaction(tx, result, dbSessionId);
   309→        }
   310→      });
   311→    } catch (error) {
   312→      throw new Error(
   313→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   314→      );
   315→    }
   316→  }
   317→
   318→  /**
   319→   * Build classification stage data from explainability trace
   320→   */
   321→  private buildStageData(
   322→    result: ClassificationResult,
   323→    sessionId: bigint
   324→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   325→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   326→    const trace = result.explainabilityTrace;
   327→
   328→    // Map pipeline stages to database records
   329→    const stageMapping = [
   330→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   331→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   332→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   333→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   334→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   335→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
   336→      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
   337→      { order: 8, type: 'ai_routing', data: trace.aiRouting },
   338→      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
   339→      {
   340→        order: 10,
   341→        type: 'action_determination',
   342→        data: {
   343→          determinedActions: result.determinedActions || [],
   344→          actionReasoning: result.finalClassificationSummary?.determinedActions
   345→            ? `Actions: ${result.finalClassificationSummary.determinedActions.join(', ')}`
   346→            : 'No actions determined',
   347→        },
   348→      },
   349→    ];
   350→
   351→    for (const stage of stageMapping) {
   352→      stages.push({
   353→        sessionId: sessionId,
   354→        stageOrder: stage.order,
   355→        stageType: stage.type,
   356→        startedAt: new Date(),
   357→        endedAt: new Date(),
   358→        features: stage.data as Prisma.InputJsonValue,
   359→        keywords: [],
   360→        passedToNext: true,
   361→      });
   362→    }
   363→
   364→    return stages;
   365→  }
   366→
   367→  /**
   368→   * Build stage category evaluation data from score breakdown
   369→   */
   370→  private async buildCategoryEvalData(
   371→    result: ClassificationResult,
   372→    sessionId: bigint
   373→  ): Promise<Array<Prisma.StageCategoryEvalCreateManyInput>> {
   374→    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
   375→    const scoreBreakdown = result.scoreBreakdown;
   376→
   377→    // Extract category scores and create evaluations
   378→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   379→      try {
   380→        const categoryId = await this.getCategoryIdFromCode(category);
   381→        evaluations.push({
   382→          stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   383→          categoryId: categoryId,
   384→          decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
   385→          score: scores as unknown as Prisma.InputJsonValue,
   386→          confidence: new Prisma.Decimal(scores.finalScore || 0),
   387→          scoringComponents: scores as unknown as Prisma.InputJsonValue,
   388→          keywords: [],
   389→          createdAt: new Date(),
   390→        });
   391→      } catch (error) {
   392→        // Log warning and skip unknown category (graceful degradation)
   393→        logger.warn(
   394→          { category, error: error instanceof Error ? error.message : String(error) },
   395→          `Skipping category evaluation for unknown category '${category}'`
   396→        );
   397→      }
   398→    }
   399→
   400→    return evaluations;
   401→  }
   402→
   403→  /**
   404→   * Build session category data (multi-label support)
   405→   */
   406→  private async buildSessionCategoryData(
   407→    result: ClassificationResult,
   408→    sessionId: bigint
   409→  ): Promise<Array<Prisma.SessionCategoryCreateManyInput>> {
   410→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   411→
   412→    for (const label of result.selectedLabels) {
   413→      try {
   414→        const categoryId = await this.getCategoryIdFromCode(label.category);
   415→        const subtypeId = label.subtype ? await this.getCategoryIdFromCode(label.subtype) : null;
   416→
   417→        categories.push({
   418→          sessionId: sessionId,
   419→          categoryId: categoryId,
   420→          subtypeId: subtypeId,
   421→          isPrimary: label.isPrimary,
   422→          confidence: new Prisma.Decimal(label.confidence),
   423→          categoryScore: new Prisma.Decimal(label.score),
   424→          hardAssertion: false, // TODO: Extract from explainability trace
   425→          aiClassified: result.aiRoutingUsed,
   426→          scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   427→          labelOrder: label.labelOrder,
   428→          createdAt: new Date(),
   429→        });
   430→      } catch (error) {
   431→        // Log warning and skip unknown category (graceful degradation)
   432→        logger.warn(
   433→          { category: label.category, error: error instanceof Error ? error.message : String(error) },
   434→          `Skipping session category for unknown category '${label.category}'`
   435→        );
   436→      }
   437→    }
   438→
   439→    return categories;
   440→  }
   441→
   442→  /**
   443→   * Build detected attribute data from attribute context
   444→   *
   445→   * Maps attribute context to database records with complete detection metadata,
   446→   * influence tracking, and temporal signals. Handles:
   447→   * - Urgency levels with detection metadata
   448→   * - Domain attributes with influence tracking
   449→   * - Structural patterns with evidence
   450→   * - Temporal signals (time-based patterns, scheduling info)
   451→   * - Influence applications with score impacts (attribute bonuses/penalties)
   452→   * - Derived attributes (computed from base attributes)
   453→   *
   454→   * @param context - AttributeContext with detected attributes and metadata
   455→   * @param sessionId - Session identifier as bigint
   456→   * @returns Array of detected attribute records for database insertion
   457→   */
   458→  private buildAttributeData(
   459→    context: AttributeContext,
   460→    sessionId: bigint
   461→  ): Array<Prisma.DetectedAttributeCreateManyInput> {
   462→    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];
   463→
   464→    // Helper to extract detection metadata
   465→    const getDetectionMetadata = (attributeKey: string) => {
   466→      return context.detectionMetadata?.[attributeKey];
   467→    };
   468→
   469→    // Helper to find influence applications for an attribute
   470→    const getInfluenceData = (attributeName: string) => {
   471→      const influences = context.influenceApplications?.filter((app) => app.attributeUsed === attributeName) || [];
   472→      const categoriesInfluenced = influences.map((app) => app.targetCategory);
   473→      const totalBonus = influences.reduce((sum, app) => sum + app.scoreImpact, 0);
   474→      const primaryRole = influences.length > 0 ? influences[0].roleType : 'NEUTRAL';
   475→      return { categoriesInfluenced, totalBonus, primaryRole };
   476→    };
   477→
   478→    // 1. Add urgency attribute
   479→    const urgencyMetadata = getDetectionMetadata('urgency');
   480→    const urgencyInfluence = getInfluenceData('urgency');
   481→    attributes.push({
   482→      sessionId: sessionId,
   483→      attributeName: 'urgency',
   484→      attributeValue: context.urgency,
   485→      detectionMethod: urgencyMetadata?.detectionMethod || 'rule',
   486→      detectionEvidence: urgencyMetadata?.evidence || `Urgency level: ${context.urgency}`,
   487→      influenceRole: urgencyInfluence.primaryRole,
   488→      categoriesInfluenced: urgencyInfluence.categoriesInfluenced,
   489→      totalBonusApplied: new Prisma.Decimal(urgencyInfluence.totalBonus),
   490→      createdAt: new Date(),
   491→    });
   492→
   493→    // 2. Add domain attributes
   494→    for (const domain of context.domains) {
   495→      const domainKey = `domain:${domain}`;
   496→      const domainMetadata = getDetectionMetadata(domainKey);
   497→      const domainInfluence = getInfluenceData(domainKey);
   498→
   499→      attributes.push({
   500→        sessionId: sessionId,
   501→        attributeName: domainKey,
   502→        attributeValue: domain,
   503→        detectionMethod: domainMetadata?.detectionMethod || 'domainLookup',
   504→        detectionEvidence: domainMetadata?.evidence || `Domain ${domain} detected in email`,
   505→        influenceRole: domainInfluence.primaryRole,
   506→        categoriesInfluenced: domainInfluence.categoriesInfluenced,
   507→        totalBonusApplied: new Prisma.Decimal(domainInfluence.totalBonus),
   508→        createdAt: new Date(),
   509→      });
   510→    }
   511→
   512→    // 3. Add structural pattern attributes
   513→    for (const pattern of context.structuralPatterns) {
   514→      const patternKey = `pattern:${pattern}`;
   515→      const patternMetadata = getDetectionMetadata(patternKey);
   516→      const patternInfluence = getInfluenceData(patternKey);
   517→
   518→      attributes.push({
   519→        sessionId: sessionId,
   520→        attributeName: patternKey,
   521→        attributeValue: pattern,
   522→        detectionMethod: patternMetadata?.detectionMethod || 'pattern',
   523→        detectionEvidence: patternMetadata?.evidence || `Structural pattern ${pattern} matched`,
   524→        influenceRole: patternInfluence.primaryRole,
   525→        categoriesInfluenced: patternInfluence.categoriesInfluenced,
   526→        totalBonusApplied: new Prisma.Decimal(patternInfluence.totalBonus),
   527→        createdAt: new Date(),
   528→      });
   529→    }
   530→
   531→    // 4. Add temporal signal attributes (time-sensitive keywords, deadline indicators)
   532→    for (const signal of context.temporalSignals) {
   533→      const signalKey = `temporal:${signal}`;
   534→      const signalMetadata = getDetectionMetadata(signalKey);
   535→      const signalInfluence = getInfluenceData(signalKey);
   536→
   537→      attributes.push({
   538→        sessionId: sessionId,
   539→        attributeName: signalKey,
   540→        attributeValue: signal,
   541→        detectionMethod: signalMetadata?.detectionMethod || 'temporalAnalysis',
   542→        detectionEvidence:
   543→          signalMetadata?.evidence || `Temporal signal ${signal} detected (e.g., time-sensitive keywords, deadlines)`,
   544→        influenceRole: signalInfluence.primaryRole,
   545→        categoriesInfluenced: signalInfluence.categoriesInfluenced,
   546→        totalBonusApplied: new Prisma.Decimal(signalInfluence.totalBonus),
   547→        createdAt: new Date(),
   548→      });
   549→    }
   550→
   551→    // 5. Add derived attributes computed from other attributes
   552→    // Examples: is_self_sent (from/to comparison), email_age (timestamp calculation)
   553→    for (const [derivedKey, derivedResult] of Object.entries(context.derivedAttributes || {})) {
   554→      const derivedInfluence = getInfluenceData(derivedKey);
   555→
   556→      attributes.push({
   557→        sessionId: sessionId,
   558→        attributeName: derivedKey,
   559→        attributeValue: String(derivedResult.calculatedValue),
   560→        detectionMethod: 'derived',
   561→        detectionEvidence: `Derived from: ${derivedResult.sourceAttributes.join(', ')} via ${derivedResult.derivationLogic}`,
   562→        influenceRole: derivedInfluence.primaryRole,
   563→        categoriesInfluenced: derivedInfluence.categoriesInfluenced,
   564→        totalBonusApplied: new Prisma.Decimal(derivedInfluence.totalBonus),
   565→        createdAt: new Date(),
   566→      });
   567→    }
   568→
   569→    // 6. Add influence applications that don't map to specific detected attributes
   570→    // These represent context-dependent influences (attribute combinations, conditional bonuses)
   571→    // that don't correspond to individual urgency/domain/pattern/temporal/derived detections
   572→    const coveredAttributes = new Set([
   573→      'urgency',
   574→      ...context.domains.map((d) => `domain:${d}`),
   575→      ...context.structuralPatterns.map((p) => `pattern:${p}`),
   576→      ...context.temporalSignals.map((s) => `temporal:${s}`),
   577→      ...Object.keys(context.derivedAttributes || {}),
   578→    ]);
   579→
   580→    for (const influence of context.influenceApplications || []) {
   581→      if (!coveredAttributes.has(influence.attributeUsed)) {
   582→        // This is an influence from an attribute not explicitly tracked above
   583→        // (e.g., attribute combinations, implicit signals)
   584→        const metadata = getDetectionMetadata(influence.attributeUsed);
   585→
   586→        attributes.push({
   587→          sessionId: sessionId,
   588→          attributeName: influence.attributeUsed,
   589→          attributeValue: 'implicit', // No explicit value, inferred from influence
   590→          detectionMethod: metadata?.detectionMethod || 'derived',
   591→          detectionEvidence:
   592→            metadata?.evidence || `Implicit influence on ${influence.targetCategory}: ${influence.applicationReason}`,
   593→          influenceRole: influence.roleType,
   594→          categoriesInfluenced: [influence.targetCategory],
   595→          totalBonusApplied: new Prisma.Decimal(influence.scoreImpact),
   596→          createdAt: new Date(),
   597→        });
   598→
   599→        // Mark as covered to avoid duplicates
   600→        coveredAttributes.add(influence.attributeUsed);
   601→      }
   602→    }
   603→
   604→    return attributes;
   605→  }
   606→
   607→  /**
   608→   * Build extracted feature data from AI feature extraction results
   609→   *
   610→   * Extracts AI-generated features from the explainability trace and creates
   611→   * database records linked to the AI routing stage (stage 8).
   612→   *
   613→   * Only called when AI routing was used (result.aiRoutingUsed = true).
   614→   *
   615→   * @param result - ClassificationResult with AI feature extraction data
   616→   * @param stageRecords - Created classification stages with IDs
   617→   * @returns Array of extracted feature records for database insertion
   618→   */
   619→  private buildExtractedFeatureData(
   620→    result: ClassificationResult,
   621→    stageRecords: Array<{ stageId: bigint; stageOrder: number }>
   622→  ): Array<Prisma.ExtractedFeatureCreateManyInput> {
   623→    const features: Array<Prisma.ExtractedFeatureCreateManyInput> = [];
   624→
   625→    // Find the AI routing stage (stage 8) to associate features with
   626→    const aiRoutingStage = stageRecords.find((stage) => stage.stageOrder === 8);
   627→    if (!aiRoutingStage) {
   628→      logger.warn('AI routing stage not found in stage records, skipping feature extraction persistence');
   629→      return features;
   630→    }
   631→
   632→    // Extract AI feature extraction data from explainability trace
   633→    const aiResponse = result.explainabilityTrace?.aiRouting?.aiResponse;
   634→    if (!aiResponse?.extractedFeatures) {
   635→      // No AI features to persist (AI routing may have skipped feature extraction)
   636→      return features;
   637→    }
   638→
   639→    const extractedFeatures = aiResponse.extractedFeatures as {
   640→      semanticIntent?: {
   641→        primaryPurpose?: string;
   642→        actionRequired?: string;
   643→        urgencyLevel?: string;
   644→      };
   645→      categoryEnhancements?: Record<
   646→        string,
   647→        {
   648→          applies: boolean;
   649→          confidenceBoost: number;
   650→          evidence?: {
   651→            quotedPhrases?: string[];
   652→            keywords?: string[];
   653→            reasoning?: string;
   654→          };
   655→        }
   656→      >;
   657→    };
   658→
   659→    // Extract semantic intent features
   660→    if (extractedFeatures.semanticIntent) {
   661→      const intent = extractedFeatures.semanticIntent;
   662→
   663→      if (intent.primaryPurpose) {
   664→        features.push({
   665→          stageId: aiRoutingStage.stageId,
   666→          name: 'semantic_intent_primary_purpose',
   667→          value: intent.primaryPurpose,
   668→          importance: new Prisma.Decimal(0.8), // High importance for primary purpose
   669→          evidenceSnippet: null,
   670→          createdAt: new Date(),
   671→        });
   672→      }
   673→
   674→      if (intent.actionRequired) {
   675→        features.push({
   676→          stageId: aiRoutingStage.stageId,
   677→          name: 'semantic_intent_action_required',
   678→          value: intent.actionRequired,
   679→          importance: new Prisma.Decimal(0.7),
   680→          evidenceSnippet: null,
   681→          createdAt: new Date(),
   682→        });
   683→      }
   684→
   685→      if (intent.urgencyLevel) {
   686→        features.push({
   687→          stageId: aiRoutingStage.stageId,
   688→          name: 'semantic_intent_urgency_level',
   689→          value: intent.urgencyLevel,
   690→          importance: new Prisma.Decimal(0.6),
   691→          evidenceSnippet: null,
   692→          createdAt: new Date(),
   693→        });
   694→      }
   695→    }
   696→
   697→    // Extract category enhancement features
   698→    if (extractedFeatures.categoryEnhancements) {
   699→      for (const [category, enhancement] of Object.entries(extractedFeatures.categoryEnhancements)) {
   700→        if (enhancement.applies && enhancement.confidenceBoost > 0) {
   701→          // Create a feature record for this category enhancement
   702→          const evidenceSnippet =
   703→            enhancement.evidence?.quotedPhrases && enhancement.evidence.quotedPhrases.length > 0
   704→              ? enhancement.evidence.quotedPhrases.slice(0, 3).join(' | ') // First 3 quoted phrases
   705→              : enhancement.evidence?.reasoning || null;
   706→
   707→          features.push({
   708→            stageId: aiRoutingStage.stageId,
   709→            name: `category_enhancement_${category}`,
   710→            value: `boost:${enhancement.confidenceBoost}`,
   711→            importance: new Prisma.Decimal(Math.min(enhancement.confidenceBoost / 100, 1.0)), // Normalize to 0-1
   712→            evidenceSnippet: evidenceSnippet ? evidenceSnippet.substring(0, 500) : null, // Limit length
   713→            createdAt: new Date(),
   714→          });
   715→
   716→          // If there are keywords, create a separate feature for them
   717→          if (enhancement.evidence?.keywords && enhancement.evidence.keywords.length > 0) {
   718→            features.push({
   719→              stageId: aiRoutingStage.stageId,
   720→              name: `category_keywords_${category}`,
   721→              value: enhancement.evidence.keywords.slice(0, 10).join(', '), // First 10 keywords
   722→              importance: new Prisma.Decimal(0.5),
   723→              evidenceSnippet: null,
   724→              createdAt: new Date(),
   725→            });
   726→          }
   727→        }
   728→      }
   729→    }
   730→
   731→    return features;
   732→  }
   733→
   734→  /**
   735→   * Get category ID from category code
   736→   *
   737→   * Uses cached category lookup for performance. Cache is initialized
   738→   * on first use and persists for the lifetime of the repository instance.
   739→   *
   740→   * @param code - Category code (e.g., 'finance', 'personal')
   741→   * @returns Category ID from database
   742→   * @throws {Error} If category code not found in database
   743→   */
   744→  private async getCategoryIdFromCode(code: string): Promise<number> {
   745→    // Initialize cache on first use
   746→    if (this.categoryCache === null) {
   747→      await this.initializeCategoryCache();
   748→    }
   749→
   750→    const categoryId = this.categoryCache!.get(code);
   751→    if (categoryId === undefined) {
   752→      throw new Error(
   753→        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
   754→      );
   755→    }
   756→
   757→    return categoryId;
   758→  }
   759→
   760→  /**
   761→   * Close the Prisma client connection
   762→   *
   763→   * Only closes if using default Prisma instance (not externally provided).
   764→   */
   765→  async close(): Promise<void> {
   766→    if (this.ownsPrisma) {
   767→      await this.prisma.$disconnect();
   768→    }
   769→  }
   770→}
   771→

