    return {
      attributeName: 'fromNewsletterSource',
      attributeValue: true,
      detectionMethod: 'derived',
      detectionEvidence: 'List-Id header present',
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Derive fromLogisticsCarrier attribute
 */
function deriveFromLogisticsCarrier(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const logisticsDomains = getLogisticsDomains(config);

  if (logisticsDomains.includes(fromDomain)) {
    return {
      attributeName: 'fromLogisticsCarrier',
      attributeValue: true,
      detectionMethod: 'domainLookup',
      detectionEvidence: fromDomain,
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Extract base domain from email address
 */
function extractBaseDomain(email: string): string {
  const domainPart = email.split('@')[1];
  if (!domainPart) return '';

  // Handle subdomains - return main domain for common patterns
  const parts = domainPart.split('.');
  if (parts.length >= 2) {
    return parts.slice(-2).join('.');
  }
  return domainPart;
}

/**
 * Get user email addresses for selfSent detection
 */
function getUserAddresses(): string[] {
  // In real implementation, this would come from user configuration
  return ['user@gmail.com', 'scotthamilton77@gmail.com'];
}

/**
 * Get financial domains for institution detection
 */
function getFinancialDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.financialDomains || [];
}

/**
 * Get newsletter domains for source detection
 */
function getNewsletterDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.newsletterDomains || [];
}

/**
 * Get logistics domains for carrier detection
 */
function getLogisticsDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.logisticsDomains || [];
}

/**
 * Derive Gmail category attributes from Gmail API labelIds (configuration-driven)
 *
 * Gmail automatically categorizes emails into Social, Promotions, and Updates.
 * These categories are exposed via Gmail API as labelIds.
 *
 * This function iterates over the configured Gmail category mappings to detect
 * which categories apply to the email, enabling customization without code changes.
 * Mappings are provided via config.attributes.gmailCategoryMapping (Zod schema ensures defaults).
 *
 * @param email - Email message with gmailLabels from Gmail API
 * @param config - Stage configuration with gmailCategoryMapping (provided by Zod default)
 * @returns Detected Gmail category attributes based on configuration
 */
function deriveGmailCategories(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
  const gmailLabels = email.gmailLabels || [];
  const detectedAttributes: DetectedAttribute[] = [];

  // Iterate over configured mappings (Zod schema provides default if not in config file)
  for (const mapping of config.attributes.gmailCategoryMapping) {
    if (gmailLabels.includes(mapping.categoryLabel)) {
      detectedAttributes.push({
        attributeName: mapping.attributeName,
        attributeValue: true,
        detectionMethod: 'derived',
        detectionEvidence: `Gmail labeled as ${mapping.categoryLabel}`,
        confidence: mapping.confidence,
      });
    }
  }

  return detectedAttributes;
}

/**
 * Detect urgency level from email content and headers
 *
 * Analyzes subject, body, and X-Priority header to determine urgency level.
 * Returns one of: 'none', 'low', 'medium', 'high' (matching config schema)
 *
 * TODO: Make this configuration-driven rather than hardcoded
 * Suggested approach: Add urgency detectors to config.processingConfig.attributes.detectors
 * with tier-based patterns similar to rule-based classification:
 * {
 *   "attribute": "urgency",
 *   "tiers": {
 *     "high": { patterns: [...], headerConditions: { "X-Priority": [1, 2] } },
 *     "medium": { patterns: [...], headerConditions: { "X-Priority": [3] } },
 *     "low": { patterns: [...] },
 *     "none": { isDefault: true }
 *   }
 * }
 *
 * Current hardcoded patterns:
 *
 * High urgency indicators:
 * - Keywords: "urgent", "immediately", "asap", "critical", "emergency", "overdue", "action required"
 * - X-Priority header: 1 or 2
 *
 * Medium urgency indicators:
 * - Keywords: "soon", "important", "please review", "time sensitive"
 * - X-Priority header: 3
 *
 * Low urgency indicators:
 * - Keywords: "fyi", "no rush", "when you have time", "at your convenience"
 * - X-Priority header: 4 or 5
 *
 * None urgency: No urgency indicators detected (current default)
 */
function detectUrgency(email: EmailMessage): 'none' | 'low' | 'medium' | 'high' {
  const subject = (email.subject || '').toLowerCase();
  const body = extractEmailBodyText(email).toLowerCase();
  const contentText = `${subject} ${body}`;

  // Check X-Priority header (1 = highest, 5 = lowest)
  const xPriority = email.payload?.headers?.find((h) => h.name.toLowerCase() === 'x-priority')?.value;
  const priorityNum = xPriority ? parseInt(xPriority, 10) : null;

  // High urgency patterns
  const highUrgencyKeywords = [
    'urgent',
    'immediately',
    'asap',
    'critical',
    'emergency',
    'overdue',
    'action required',
    'respond immediately',
    'time-sensitive',
  ];

  // Medium urgency patterns
  const mediumUrgencyKeywords = [
    'soon',
    'important',
    'please review',
    'time sensitive',
    'attention needed',
    'follow up',
  ];

  // Low urgency patterns
  const lowUrgencyKeywords = ['fyi', 'for your information', 'no rush', 'when you have time', 'at your convenience'];

  // Check for high urgency
  if (priorityNum !== null && priorityNum <= 2) {
    return 'high';
  }

  for (const keyword of highUrgencyKeywords) {
    if (contentText.includes(keyword)) {
      return 'high';
    }
  }

  // Check for medium urgency
  if (priorityNum === 3) {
    return 'medium';
  }

  for (const keyword of mediumUrgencyKeywords) {
    if (contentText.includes(keyword)) {
      return 'medium';
    }
  }

  // Check for explicit low urgency (X-Priority 4 or 5)
  if (priorityNum !== null && priorityNum >= 4) {
    return 'low';
  }

  // Check for low urgency keywords
  for (const keyword of lowUrgencyKeywords) {
    if (contentText.includes(keyword)) {
      return 'low';
    }
  }

  // Default to 'none' (no urgency indicators detected)
  // This matches config schema which includes "none" as a valid value
  return 'none';
}

