  describe('Performance Requirements', () => {
    test('should complete processing within reasonable time', () => {
      const { session, result } = setupTestEnvironment();
      const startTime = Date.now();

      executeAttributeDetection(createMockEmail(), session, result, stageConfig);

      const endTime = Date.now();
      const processingTime = endTime - startTime;

      expect(processingTime).toBeLessThan(1000);
      expect(result.explainabilityTrace.stageTimings['attributeDetection']).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings['attributeDetection']).toBeLessThan(1000);
    });

    test('should handle batch processing efficiently', () => {
      const emails = Array(10)
        .fill(null)
        .map((_, i) =>
          createMockEmail({
            id: `test_email_${i}`,
            bodyPlain: `Test email body with amount $${i * 10}.00`,
          })
        );

      const startTime = Date.now();

      const results: Array<{ result: ClassificationResult; detectedAttrs: AttributeDetectionResult[] }> = [];
      emails.forEach((email) => {
        const { session, result } = setupTestEnvironment({}, { id: email.id }, 'parallel');
        const detectedAttrs = executeAttributeDetection(email, session, result, stageConfig);
        results.push({ result, detectedAttrs });
      });

      const endTime = Date.now();
      const totalTime = endTime - startTime;

      expect(results).toHaveLength(10);
      expect(totalTime).toBeLessThan(5000);

      results.forEach(({ detectedAttrs }) => {
        const detectedAttributes = detectedAttrs.map((attr) => ({
          attributeName: attr.attribute,
          attributeValue: attr.detected,
          detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
          detectionEvidence: attr.reason || '',
          confidence: attr.confidence,
        }));
        expect(detectedAttributes).toContainEqual(
          expect.objectContaining({
            attributeName: 'hasAmount',
            attributeValue: true,
          })
        );
      });
    });
  });

